import { fromCognitoIdentityPool } from "@aws-sdk/credential-providers";
import { buildAuthHelper } from "../common/authHelper";
/**
 * Creates an auth helper instance using credentials from Cognito.
 *
 * @param identityPoolId Cognito Identity Pool Id
 */
export async function withIdentityPoolId(identityPoolId, options) {
    const region = identityPoolId.split(":")[0];
    const credentialProvider = fromCognitoIdentityPool(Object.assign(Object.assign({}, (options || {})), { identityPoolId, clientConfig: Object.assign(Object.assign({}, (options && options.clientConfig ? options.clientConfig : {})), { region }) }));
    return buildAuthHelper(credentialProvider, region);
}
